// Read current shared state (persists across messages)
let s = flow.get('binState') || {
  wet_pct: 0, dry_pct: 0,
  wet_dist: 17, dry_dist: 17,
  wet_status: 'OK', dry_status: 'OK',
  temp_c: 0, humid_pct: 0, leak: false,
  total_sorted: 0, total_wet: 0, total_dry: 0,
  uptime_s: 0,
  last_alert: '',
  last_sort: '',
  _prev_wet_status: 'OK',
  _prev_dry_status: 'OK',
  log: []
};

// Handle payload as either a raw JSON string OR an already-parsed object.
// Some MQTT nodes (e.g. datatype:auto-detect) pre-parse the JSON so
// msg.payload arrives as an object instead of a string.
let data;
try {
  data = (typeof msg.payload === 'object' && msg.payload !== null)
    ? msg.payload
    : JSON.parse(msg.payload);
} catch(e) { return null; }

const now = new Date().toLocaleTimeString('en-GB', { hour12: false });

function pushLog(text, level) {
  s.log.unshift({ time: now, msg: text, level: level || 'info' });
  if (s.log.length > 50) s.log.pop();
}

// ── Bin levels ──────────────────────────────────────────────────
if (msg.topic === 'smartbin/bin/levels') {
  s.wet_pct  = typeof data.wet_pct  === 'number' ? parseFloat(data.wet_pct.toFixed(2))  : s.wet_pct;
  s.dry_pct  = typeof data.dry_pct  === 'number' ? parseFloat(data.dry_pct.toFixed(2))  : s.dry_pct;
  s.wet_dist = typeof data.wet_dist === 'number' ? parseFloat(data.wet_dist.toFixed(1)) : s.wet_dist;
  s.dry_dist = typeof data.dry_dist === 'number' ? parseFloat(data.dry_dist.toFixed(1)) : s.dry_dist;

  const newWetStatus = data.wet_status || s.wet_status;
  const newDryStatus = data.dry_status || s.dry_status;

  if (newWetStatus === 'NEAR_FULL' && s._prev_wet_status !== 'NEAR_FULL') {
    pushLog('Wet bin nearly full (' + s.wet_pct.toFixed(0) + '%) — consider replacing soon', 'warn');
  }
  if (newDryStatus === 'NEAR_FULL' && s._prev_dry_status !== 'NEAR_FULL') {
    pushLog('Dry bin nearly full (' + s.dry_pct.toFixed(0) + '%) — consider replacing soon', 'warn');
  }
  if (newWetStatus === 'OK' && s._prev_wet_status !== 'OK') {
    pushLog('Wet bin cleared — back to normal', 'info');
  }
  if (newDryStatus === 'OK' && s._prev_dry_status !== 'OK') {
    pushLog('Dry bin cleared — back to normal', 'info');
  }

  s._prev_wet_status = newWetStatus;
  s._prev_dry_status = newDryStatus;
  s.wet_status = newWetStatus;
  s.dry_status = newDryStatus;
}

// ── Environment ─────────────────────────────────────────────────
else if (msg.topic === 'smartbin/environment') {
  s.temp_c    = typeof data.temp_c    === 'number' ? parseFloat(data.temp_c.toFixed(1))    : s.temp_c;
  s.humid_pct = typeof data.humid_pct === 'number' ? parseFloat(data.humid_pct.toFixed(1)) : s.humid_pct;
  s.leak      = !!data.leak;
}

// ── Alerts ──────────────────────────────────────────────────────
else if (msg.topic === 'smartbin/alerts') {
  const labels = {
    BIN_FULL:      '🗑 Bin Full — please replace immediately',
    FIRE_RISK:     '🔥 FIRE RISK — temperature exceeded 50°C!',
    LIQUID_LEAK:   '💧 Liquid Leak — float switch triggered',
    TEMP_WARNING:  '🌡 Temp Warning — temperature 45–50°C',
    HIGH_HUMIDITY: '💦 High Humidity — above 80%'
  };
  const level = ['FIRE_RISK','LIQUID_LEAK'].includes(data.type) ? 'alert'
               : ['BIN_FULL','TEMP_WARNING','HIGH_HUMIDITY'].includes(data.type) ? 'warn'
               : 'info';
  s.last_alert = labels[data.type] || data.type;
  pushLog(s.last_alert, level);
}

// ── Sort events ─────────────────────────────────────────────────
else if (msg.topic === 'smartbin/sort/event') {
  s.total_sorted = data.total_sorted || s.total_sorted;
  s.total_wet    = data.total_wet    || s.total_wet;
  s.total_dry    = data.total_dry    || s.total_dry;
  const typeIcon = data.type === 'WET' ? '💧' : '📦';
  const sortMsg  = typeIcon + ' ' + (data.type || '?') + ' waste sorted — total: ' + s.total_sorted;
  s.last_sort    = sortMsg;
  pushLog(sortMsg, 'info');
}

// ── Heartbeat — update uptime silently, NO log entry ───────────
else if (msg.topic === 'smartbin/system/heartbeat') {
  s.uptime_s     = data.uptime_s     || s.uptime_s;
  s.total_sorted = data.total_sorted || s.total_sorted;
}

// ── Control log from Firebase bridge ───────────────────────────
else if (msg.topic === 'smartbin/control/log') {
  pushLog(data.msg || 'Dashboard action', data.level || 'info');
}

flow.set('binState', s);
return { payload: s, topic: msg.topic };

msg.method = "PUT";
msg.url = "https://smart-bin-78f35-default-rtdb.asia-southeast1.firebasedatabase.app/smartbin/live/bin01.json";

msg.headers = {
    "Content-Type": "application/json"
};

// Format: "2026-04-07 15:57:46 UTC"  (no T, no milliseconds)
var ts = new Date().toISOString().replace('T', ' ').replace(/\.\d{3}Z$/, ' UTC');

msg.payload = {
    ...msg.payload,
    updated_at: ts
};

return msg;

if (msg.topic !== 'smartbin/sort/event' && msg.topic !== 'smartbin/alerts') return null;

var s = flow.get('binState') || {};
// Key = ISO timestamp e.g. 2026-04-07T15:57:46 (human-readable, sorts correctly)
var key = new Date().toISOString().replace(/\.\d{3}Z$/, '');

msg.method  = "PUT";
msg.url     = "https://smart-bin-78f35-default-rtdb.asia-southeast1.firebasedatabase.app/smartbin/history/bin01/" + key + ".json";
msg.headers = { "Content-Type": "application/json" };
var ts = new Date().toISOString().replace('T', ' ').replace(/\.\d{3}Z$/, ' UTC');
msg.payload = {
    time:         ts,
    event:        msg.topic === 'smartbin/sort/event' ? 'sort' : 'alert',
    temp_c:       s.temp_c       || 0,
    humid_pct:    s.humid_pct    || 0,
    wet_pct:      s.wet_pct      || 0,
    dry_pct:      s.dry_pct      || 0,
    total_sorted: s.total_sorted || 0,
    total_wet:    s.total_wet    || 0,
    total_dry:    s.total_dry    || 0
};
return msg;

// Receives GET response from Firebase /smartbin/control.json
// payload is the parsed JSON object (or null if no pending commands)
var ctrl = msg.payload;

// null means no pending commands — nothing to do
if (!ctrl || typeof ctrl !== 'object' || Array.isArray(ctrl)) return null;

var topicMap = {
    'servo':    'smartbin/control/servo',
    'dht11':    'smartbin/control/dht11',
    'led':      'smartbin/control/led',
    'moisture': 'smartbin/control/moisture'
};

var mqttMsgs = [];
var hasAny = false;

for (var key in ctrl) {
    if (ctrl[key] !== null && ctrl[key] !== undefined && topicMap[key]) {
        hasAny = true;
        var body = ctrl[key];

        // MQTT control message
        mqttMsgs.push({
            topic: topicMap[key],
            payload: typeof body === 'string' ? body : JSON.stringify(body)
        });

        // Build activity log entry
        var logText = '';
        var logLevel = 'info';
        if (key === 'servo') {
            logText = '⚙ Servo updated — Dry: ' + (body.dry_deg || '?') + '°  Wet: ' + (body.wet_deg || '?') + '°';
        } else if (key === 'dht11') {
            logText = '🌡 DHT11 sensor ' + (body.enabled ? 'enabled' : 'disabled') + ' from dashboard';
            logLevel = body.enabled ? 'info' : 'warn';
        } else if (key === 'led') {
            logText = '💡 LED indicators ' + (body.enabled ? 'enabled' : 'disabled') + ' from dashboard';
            logLevel = body.enabled ? 'info' : 'warn';
        } else if (key === 'moisture') {
            logText = '💧 Moisture sensor ' + (body.enabled ? 'enabled' : 'disabled') + ' from dashboard';
            if (!body.enabled) logText += ' (forced DRY mode)';
            logLevel = body.enabled ? 'info' : 'warn';
        }
        if (logText) {
            mqttMsgs.push({
                topic: 'smartbin/control/log',
                payload: JSON.stringify({ msg: logText, level: logLevel })
            });
        }
    }
}

if (!hasAny) return null;

// Build PATCH request to clear all processed control keys from Firebase
// Setting a key to null via PATCH removes it in Firebase REST API
var clearObj = {};
for (var k in ctrl) { clearObj[k] = null; }

var patchMsg = {
    method: 'PATCH',
    url: 'https://smart-bin-78f35-default-rtdb.asia-southeast1.firebasedatabase.app/smartbin/control.json',
    headers: { 'Content-Type': 'application/json' },
    payload: clearObj
};

node.warn('Firebase control received: ' + JSON.stringify(ctrl));

// Output 1: array of MQTT messages (control + log)
// Output 2: PATCH message to clear Firebase control
return [mqttMsgs, patchMsg];

// Step 1 of 3: save ESP32 date, then fetch live data from Firebase.
// flow.get('binState') is in-memory and resets when Node-RED restarts,
// so Firebase is the only reliable source of truth across device changes.
var data = {};
try {
    data = (typeof msg.payload === 'object' && msg.payload !== null)
        ? msg.payload : JSON.parse(msg.payload);
} catch(e) {}

flow.set('sync_esp_date', data.date || '');

msg.method = 'GET';
msg.url    = 'https://smart-bin-78f35-default-rtdb.asia-southeast1.firebasedatabase.app/smartbin/live/bin01.json';
return msg;

// Step 3 of 3: Firebase live data is in msg.payload.
// Compare dates (all in Malaysia time UTC+8) and reply to ESP32.
var liveData = msg.payload || {};
var espDate  = flow.get('sync_esp_date') || '';

// Today in Malaysia time (UTC+8)
var now      = new Date();
var myt      = new Date(now.getTime() + 8 * 3600 * 1000);
var todayMYT = myt.toISOString().split('T')[0];

// Convert Firebase updated_at to Malaysia date
// Format stored: '2026-04-07 15:57:46 UTC'
var fbMYTDate = '';
if (liveData.updated_at) {
    var d  = new Date(liveData.updated_at.replace(' UTC', 'Z').replace(' ', 'T'));
    var dm = new Date(d.getTime() + 8 * 3600 * 1000);
    fbMYTDate = dm.toISOString().split('T')[0];
}

// Restore only when ESP date, server date AND Firebase data all agree on today
var sameDay = (espDate !== '' && espDate === todayMYT && fbMYTDate === todayMYT);

msg.topic   = 'smartbin/sync_response';
msg.payload = JSON.stringify({
    total_sorted: sameDay ? (liveData.total_sorted || 0) : 0,
    total_wet:    sameDay ? (liveData.total_wet    || 0) : 0,
    total_dry:    sameDay ? (liveData.total_dry    || 0) : 0,
    new_day:      !sameDay,
    server_date:  todayMYT
});
node.warn('[Sync] ESP=' + espDate + '  FB=' + fbMYTDate + '  server=' + todayMYT + '  sameDay=' + sameDay);
return msg;

var data = {};
try {
    data = (typeof msg.payload === 'object' && msg.payload !== null)
        ? msg.payload : JSON.parse(msg.payload);
} catch(e) {}

var date = data.prev_date || '';
if (!date) { node.warn('daily_reset missing prev_date'); return null; }

msg.method  = 'PUT';
msg.url     = 'https://smart-bin-78f35-default-rtdb.asia-southeast1.firebasedatabase.app/smartbin/daily_history/bin01/' + date + '.json';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    date:  date,
    total: data.prev_sorted || 0,
    wet:   data.prev_wet    || 0,
    dry:   data.prev_dry    || 0
};
node.warn('[DailyHistory] Writing ' + date + ' total=' + msg.payload.total + ' wet=' + msg.payload.wet + ' dry=' + msg.payload.dry);
return msg;
